<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  0:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">         46</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">   IO-APIC</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">   2-edge</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      timer</span></span>
